var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"드론 격추 판정. 그래도 덕분에 저격수의 위치를 특정했어. 좌표 보내 줄게.","JPN":"ドローン撃墜判定。でも、おかげでスナイパーの位置を特定できたよ。座標を送るね。","ENG":"Drone was shot down. Still, we were able to locate the sniper. I'll send you the coordinates.","TWN":"無人機遭擊落，不過正好讓我定位到狙擊手的位置，座標我發給你。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"수신했어요, 스키너. 이동 경로는 예상대로네요.","JPN":"受信しました、スキナー。移動経路は予想どおりですね。","ENG":"Received, Skinner. Their route is just as we expected.","TWN":"收到，史金納。對方的移動路線和預估的一樣。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"거리가 너무 먼데. 제일 가까운 동선도 우리 무기로는 견제하기 어려워.","JPN":"距離が遠すぎるよ。一番近いルートもこっちの武器では牽制が難しい。","ENG":"They're too far, though. Even the shortest route would be too far for our weapons.","TWN":"目標距離太遠，就算是最近的路線，憑我們的武器也很難牽制。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"격추 직전에 촬영된 영상을 분석했을 때, 37m 전방에 적 병력이 매복 중이야.","JPN":"撃墜寸前に撮られた映像を分析したところ、37ｍ前方に敵の兵力が待ち伏せしてたわ。","ENG":"I've analyzed the drone cam just before it was shot down. The enemy is hiding about 37 meters in front.","TWN":"從被擊落之前拍到的影片分析結果來看，前方37m處有敵方兵力埋伏。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"최소 2명. 그 중 한 명은 유탄 발사기를 부착하고 있던 인원이야.","JPN":"最低2名。そのうちの一人は榴弾発射機をつけてた。","ENG":"Two targets, minimum. One of them is the one holding a grenade launcher.","TWN":"至少2人，其中一人身上有榴彈發射器。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쳇, 여기만 넘어가면 저 자식들 거점인데. 코앞에서 막혔네.","JPN":"チッ、ここさえ通ればあいつらの拠点なのに。目前にして行き詰まったか。","ENG":"Tsk, we're one step away from reaching their base. Blocked right in front of our noses.","TWN":"嘖，只要越過這裡就是他們的據點，竟然被擋在這裡。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우회하자, 꼬맹이. 아직 시간이 남아 있어.","JPN":"迂回しよう、おこちゃま。まだ時間が残ってる。","ENG":"Let's take a detour, kid. There's still time left.","TWN":"繞過去吧，小鬼，我們還有時間。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"40초, 아니. 38초만 기다려. 상대편 시야를 우회할 수 있게 경로 설정해 줄게.","JPN":"40秒、いや。38秒だけ待って。相手の視界を迂回する経路を設定するから。","ENG":"Wait 40, no, 38 seconds. I'll set a route for you so you can avoid getting detected.","TWN":"再等40秒，不，再等38秒。我來設定一個可以讓你繞過對方視野的路線。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아뇨. 그러다간 시간 초과예요.","JPN":"いいえ。それではタイムオーバーになります。","ENG":"No. That'll be time-out for us.","TWN":"不，繞路的話會超過時間。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"스나이퍼엔 스나이퍼로 대응하고, 우린 돌파해야 해요.","JPN":"スナイパーにはスナイパーで対応して、私たちは突破しないといけません。","ENG":"An eye for an eye. Snipers must be dealt with snipers, while we move forward.","TWN":"狙擊手就交給狙擊手對付，我們直接突破。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘, B7로 이동.","JPN":"ノエルさん、B7に移動。","ENG":"Noelle, move to B7.","TWN":"洛艾兒，前往B7。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤엑…… 헥…….","JPN":"はあ……ふえっ……","ENG":"*Huff*... *Huff*...","TWN":"呼呼……呼……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으, 너무 뛰어다녔어요……. 속이 울렁거려…….","JPN":"うう、走り回りすぎです……気分悪くなってきた……","ENG":"Uugh, I've been running so much... I feel nauseous...","TWN":"嗚嗚，跑死我了……我都快吐了……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘! B7로 움직여요!","JPN":"ノエルさん！　B7に動いて！","ENG":"Noelle! To B7, NOW!","TWN":"洛艾兒！前往B7！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 네! 수신 양호!","JPN":"あっ、はい！　受信良好！","ENG":"Oh, okay! Copy!","TWN":"喔，是！訊號接收良好！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런데 B7이 어느 쪽이었죠? 3시 방향이에요? 9시?","JPN":"ところで、B7ってどっちでしたっけ？　3時の方角？　いや、9時？","ENG":"Where was B7, by the way? On my 3? My 9?","TWN":"不過B7在哪邊？3點鐘方向嗎？還是9點鐘？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"느려요! 그렇게 어물쩡거리면 진입할 기회를 놓친다구요!","JPN":"遅い！　グズグズしてたら進入するチャンスを逃してしまいます！","ENG":"Faster! We're going to lose our chance while you hesitate!","TWN":"動作太慢！你再磨蹭下去會錯過時機的！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"펠리세트, 진정해. 다그친다고 초심자가 경력직이 되진 않아.","JPN":"フェリセット、落ち着いて。急かせたって素人が経験者になったりしないんだから。","ENG":"Relax, Félicette. Shouting won't make a newbie into an expert.","TWN":"費莉塞特，冷靜點。就算你再催促，洛艾兒也只是個新手。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"스키너, 11시 방향 건물 3층에 움직임이 있었어.","JPN":"スキナー、11時の方角のビル3階に動きがあった。","ENG":"Skinner, there was movement in the building on my 11 o'clock. Third floor.","TWN":"史金納，11點鐘方向大樓3樓有動靜。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"상대 저격수야. 우리 생각을 알아차렸나 본데.","JPN":"相手のスナイパーだ。こっちの意図に気付いたみたいだ。","ENG":"It's the enemy sniper. They must have found out what we're up to.","TWN":"是對方的狙擊手。他好像知道我們想做什麼。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"큭! 정말……!","JPN":"くっ！　もう……！","ENG":"Kgh! Really...!","TWN":"嘖！真是的……！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 뒤에 붙어요! 진입합니다!","JPN":"ライカ、後ろについて！　進入するわ！","ENG":"Laika, on my back! We're going in!","TWN":"萊卡，跟在我後面！衝進去！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"미쳤냐? 저긴 저격수까지 최소 세 명이야.","JPN":"正気か？　あっちはスナイパーまで含めて最低三人はいるんだぞ。","ENG":"Are you crazy? They have at least three people in there, including the sniper.","TWN":"你瘋了嗎？加上狙擊手，那邊至少有三個人！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하다 못해 얼빵이가 제 위치를 찾을 때까지 기다려야 정상 아냐?","JPN":"せめて間抜けが自分の位置を見つけるまで待つのが定石じゃないか？","ENG":"Shouldn't you at least wait until that goon is in position or something?","TWN":"至少應該等到小瓜呆就位吧？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"라이카 말이 맞아. 적어도 저격수만이라도 먼저 퇴장시켜야─","JPN":"ライカの言うとおりよ。少なくともスナイパーだけでも先に退場させないと―","ENG":"Laika's right. We have to get rid of the sniper fi–","TWN":"萊卡說的沒錯。至少也要先解決掉狙擊手——"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"통신 종료. 현장 판단을 우선할게요.","JPN":"通信終了。現場の判断を優先するわ。","ENG":"Ending communication. I'm prioritizing the battlefield circumstances.","TWN":"關閉通訊，現在起我會以現場判斷為準。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카는 알고 있죠? 전 저런 삼류들 상대로 우물쭈물거릴 시간 없어요.","JPN":"ライカならわかるでしょ？　私はあんな三流を相手にグズグズしている暇なんてないの。","ENG":"Laika, you get me, right? There's no time to hesitate with those mediocre amateurs.","TWN":"萊卡你知道吧？我沒時間跟那些三流隊伍耗。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"가서 결판을 내겠어요. 따라오기 싫으면 마음대로 해요.","JPN":"行って決着をつけるわ。ついて来くるのが嫌なら勝手にして。","ENG":"I'll go in and settle things. If you don't want to come, suit yourself.","TWN":"我現在就去定輸贏，來不來隨便你。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……하아, 젠장. 두 번 데뷔하다간 돌아가시겠네.","JPN":"……はあ、くそ。もう一回デビューしたら死ぬかもな。","ENG":"*Sigh*... Crap. Another debut game might just cost us our lives.","TWN":"……哀，可惡。二次比賽都給我這樣搞……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"좋아. 너 나중에 딴말 하기 없기다?","JPN":"オーケー。後で文句言うなよ？","ENG":"Fine. Don't say I didn't warn you.","TWN":"好，你以後可不要後悔！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};